#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (x[0] - x[1]) - (y[0] - y[1]);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **A = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            A[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &A[i][0], &A[i][1]);
        }
        qsort(A, N, sizeof(int *), compare);
        int sum1 = 0, sum2 = 0;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                sum1 += A[i][0];
                sum2 += A[i][1];
            } else {
                sum1 += A[i][1];
                sum2 += A[i][0];
            }
        }
        printf("%d\n", sum1 > sum2 ? sum1 : sum2);
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                printf("%d ", A[i][0]);
            } else {
                printf("%d ", A[i][1]);
            }
        }
        printf("\n");
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                printf("%d ", A[i][1]);
            } else {
                printf("%d ", A[i][0]);
            }
        }
        printf("\n");
    }
    return 0;
}

