#include <iostream>
#include <algorithm>
using namespace std;

struct Program {
    int a, b;
};

bool compare(Program x, Program y) {
    return (x.a - x.b) > (y.a - y.b);
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Program *A = new Program[N];
        for (int i = 0; i < N; i++) {
            cin >> A[i].a >> A[i].b;
        }
        sort(A, A + N, compare);
        int sum1 = 0, sum2 = 0;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                sum1 += A[i].a;
                sum2 += A[i].b;
            } else {
                sum1 += A[i].b;
                sum2 += A[i].a;
            }
        }
        cout << (sum1 > sum2 ? sum1 : sum2) << endl;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                cout << A[i].a << " ";
            } else {
                cout << A[i].b << " ";
            }
        }
        cout << endl;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                cout << A[i].b << " ";
            } else {
                cout << A[i].a << " ";
            }
        }
        cout << endl;
    }
    return 0;
}

