        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] A = new int[N][2];
            for (int i = 0; i < N; i++) {
                A[i][0] = sc.nextInt();
                A[i][1] = sc.nextInt();
            }
            Arrays.sort(A, (x, y) -> (x[0] - x[1]) - (y[0] - y[1]));
            int sum1 = 0, sum2 = 0;
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) {
                    sum1 += A[i][0];
                    sum2 += A[i][1];
                } else {
                    sum1 += A[i][1];
                    sum2 += A[i][0];
                }
            }
            System.out.println(Math.max(sum1, sum2));
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) {
                    System.out.print(A[i][0] + " ");
                } else {
                    System.out.print(A[i][1] + " ");
